function coverageTopic(question) {
  const id = question.id;
  const source = `${question.source || ''} ${question.sourceUrl || ''}`.toLowerCase();
  if (id.includes('constitucion')) return 'g1-01';
  if (id.includes('lotc') || id.startsWith('tc-')) return 'g1-02';
  if (id.includes('defensor')) return 'g1-03';
  if (id.includes('gobierno')) return 'g1-04';
  if ((id.includes('estatuto') && !id.includes('trebep')) || id === 'galicia-1') return 'g1-05';
  if (id.includes('xunta')) return 'g1-06';
  if (id.includes('elecciones')) return 'g1-07';
  if (id.includes('valedor')) return 'g1-08';
  if (id.includes('consultivo')) return 'g1-09';
  if (id.includes('ljca')) return 'g1-10';
  if (id.includes('patrimonio')) return 'g2-11';
  if (id.includes('procedimiento') || source.includes('ley 39/2015')) return 'g2-12';
  if (id.includes('regimen') || source.includes('ley 40/2015')) return 'g2-13';
  if (id.includes('financiero')) return 'g2-14';
  if (id.includes('subvenciones')) return 'g2-15';
  if (id.includes('galicia-05') || source.includes('ley 16/2010')) return 'g2-16';
  if (id.includes('contratos') || source.includes('ley 9/2017')) return 'g2-17';
  if (id.includes('trebep')) return 'g2-18';
  if (id.includes('incompatibilidades')) return 'g2-20';
  if (id.includes('igualdad')) return 'g2-21';
  if (id.includes('discapacidad')) return 'g2-22';
  if (id.includes('transparencia')) return 'g2-23';
  if (id.includes('empleo')) return 'g2-19';
  return null;
}

function coverageRows() {
  return coverageTargets.map(target => {
    const current = questions.filter(question => !question.id.startsWith('h202') && coverageTopic(question) === target.id).length;
    const percent = Math.min(100, Math.round((current / target.target) * 100));
    return { ...target, current, percent, pending: Math.max(0, target.target - current) };
  });
}

