function getStoredState() {
  try { return JSON.parse(localStorage.getItem('opoA2State') || 'null'); } catch (_) { return null; }
}

const state = getStoredState() || { goals: defaults, answered: [], errors: [], sessions: 0, current: [] };
let activeQuiz = [];
let questionIndex = 0;
let quizMode = 'practice';
let examAnswers = [];
const validViews = ['dashboard', 'practice', 'simulations', 'errors', 'library', 'syllabus', 'methodology'];
const viewHashes = {
  dashboard: 'inicio',
  practice: 'practicar',
  simulations: 'simulacros',
  errors: 'errores',
  library: 'biblioteca',
  syllabus: 'temario',
  methodology: 'metodologia'
};
const hashViews = {
  ...Object.fromEntries(Object.entries(viewHashes).map(([view, hash]) => [hash, view])),
  syllabus: 'syllabus',
  guia: 'methodology'
};

function viewFromHash() {
  const hash = decodeURIComponent(window.location.hash.replace('#', '')).trim();
  return hashViews[hash] || null;
}

function getLastView() {
  try { return localStorage.getItem('opoA2LastView'); } catch (_) { return null; }
}

function setLastView(name) {
  try { localStorage.setItem('opoA2LastView', name); } catch (_) {}
}

function persist() {
  try { localStorage.setItem('opoA2State', JSON.stringify(state)); } catch (_) {}
}
function formatCount(value) {
  return String(Math.trunc(Number(value))).replace(/\B(?=(\d{3})+(?!\d))/g, '.');
}
function showView(name, options = {}) {
  const { updateHash = true, scroll = true } = options;
  if (!validViews.includes(name)) name = 'dashboard';
  document.documentElement.dataset.activeView = name;
  document.querySelectorAll('.view').forEach(v => v.classList.toggle('active', v.id === name));
  document.querySelectorAll('.nav-link').forEach(a => a.classList.toggle('active', a.dataset.view === name));
  setLastView(name);
  if (name === 'syllabus') renderCoverage();
  if (updateHash && viewHashes[name] && window.location.hash !== `#${viewHashes[name]}`) {
    window.location.hash = viewHashes[name];
  }
  if (scroll) window.scrollTo({ top: 0, behavior: 'smooth' });
}
function updateDashboard() {
  const attempts = state.answered.length;
  const correct = state.answered.filter(a => a.correct).length;
  const net = attempts ? Math.max(0, ((correct - (attempts - correct) * .25) / attempts) * 100) : null;
  document.getElementById('dailyProgress').innerHTML = `${attempts}<span>/18</span>`;
  document.querySelector('.ring span').textContent = `${Math.min(100, Math.round((attempts / 18) * 100))}%`;
  document.getElementById('netScore').textContent = net === null ? '—' : `${Math.round(net)}%`;
  document.getElementById('averageTime').textContent = attempts ? '1:08' : '—';
  document.getElementById('pendingReviews').textContent = state.errors.length;
  document.getElementById('weeklySessions').textContent = state.sessions;

  const focusText = document.getElementById('focusCardText');
  if (focusText) {
    const block1Count = questions.filter(q => { const t = coverageTopic(q); return !q.id.startsWith('h202') && t && t.startsWith('g1-'); }).length;
    const block2Count = questions.filter(q => { const t = coverageTopic(q); return !q.id.startsWith('h202') && t && t.startsWith('g2-'); }).length;
    const b1Pct = ((block1Count / 300) * 100).toFixed(1);
    const b2Pct = ((block2Count / 910) * 100).toFixed(1);
    focusText.textContent = `${formatCount(questions.length)} preguntas en el banco (${formatCount(block1Count + block2Count)} propias + 315 de exámenes históricos). Objetivo interno de volumen: Bloque I ${formatCount(block1Count)}/300 (${b1Pct}%) y Bloque II ${formatCount(block2Count)}/910 (${b2Pct}%).`;
  }
  const snapRatio = document.getElementById('snapshotRatio');
  if (snapRatio) {
    const syllabusCount = questions.filter(q => !q.id.startsWith('h202') && Boolean(coverageTopic(q))).length;
    snapRatio.innerHTML = `${formatCount(syllabusCount)}<span>/${formatCount(1210)}</span>`;
    const snapSub = document.getElementById('snapshotSub');
    if (snapSub) snapSub.textContent = `Objetivo interno: ${formatCount(1210)} · +315 oficiales (${formatCount(questions.length)} total)`;
  }
  const b1Val = document.getElementById('valBlock1');
  if (b1Val) {
    const b1Count = questions.filter(q => { const t = coverageTopic(q); return !q.id.startsWith('h202') && t && t.startsWith('g1-'); }).length;
    const b1Pct = Math.min(100, Math.round((b1Count / 300) * 100));
    b1Val.textContent = `${formatCount(b1Count)}/300 · ${b1Pct}%`;
    const b1Bar = document.getElementById('barBlock1');
    if (b1Bar) b1Bar.style.width = `${b1Pct}%`;
  }
  const b2Val = document.getElementById('valBlock2');
  if (b2Val) {
    const b2Count = questions.filter(q => { const t = coverageTopic(q); return !q.id.startsWith('h202') && t && t.startsWith('g2-'); }).length;
    const b2Pct = Math.min(100, Math.round((b2Count / 910) * 100));
    b2Val.textContent = `${formatCount(b2Count)}/910 · ${b2Pct}%`;
    const b2Bar = document.getElementById('barBlock2');
    if (b2Bar) b2Bar.style.width = `${b2Pct}%`;
  }
}
function renderGoals() {
  const list = document.getElementById('goalsList');
  list.innerHTML = state.goals.map(goal => `<label class="goal ${goal.done ? 'done' : ''}"><input type="checkbox" data-goal="${goal.id}" ${goal.done ? 'checked' : ''}><span>${goal.text}</span><small>${goal.done ? 'hecha' : goal.progress}</small></label>`).join('');
  list.querySelectorAll('[data-goal]').forEach(box => box.addEventListener('change', e => { const goal = state.goals.find(g => g.id === e.target.dataset.goal); goal.done = e.target.checked; persist(); renderGoals(); }));
}
function renderErrors() {
  const target = document.getElementById('errorList');
  if (!state.errors.length) { target.innerHTML = '<article class="error-card empty"><p class="eyebrow">TODO DESPEJADO</p><h2>Aún no hay errores que repasar.</h2><p>Cuando una respuesta necesite consolidación, aparecerá aquí con su explicación y su fuente.</p></article>'; return; }
  target.innerHTML = state.errors.map(id => { const q = questions.find(question => question.id === id); return `<article class="error-card"><div><p class="eyebrow">${q.topic.toUpperCase()}</p><h2>${q.text}</h2><p>${q.source}</p></div><button class="secondary-button review-one" data-id="${q.id}">Repasar</button></article>`; }).join('');
  target.querySelectorAll('.review-one').forEach(button => button.addEventListener('click', () => startQuiz([questions.find(q => q.id === button.dataset.id)])));
}
function renderCoverage() {
  const rows = coverageRows();
  const current = rows.reduce((sum, row) => sum + row.current, 0);
  const target = rows.reduce((sum, row) => sum + row.target, 0);
  const percent = Math.min(100, Math.round((current / target) * 100));
  const historicalCount = questions.filter(q => q.id.startsWith('h202')).length;
  const dashboard = document.getElementById('coverageSnapshot');
  if (dashboard) {
    dashboard.innerHTML = `<div><span class="stat-label">Banco propio clasificado</span><strong id="snapshotRatio">${formatCount(current)}<span>/${formatCount(target)}</span></strong><small id="snapshotSub">Objetivo interno: ${formatCount(target)} · +${formatCount(historicalCount)} oficiales (${formatCount(questions.length)} total)</small></div><button class="secondary-button" data-view-target="syllabus">Ver avance</button>`;
    dashboard.querySelector('[data-view-target]').addEventListener('click', () => showView('syllabus'));
  }
  const summary = document.getElementById('coverageSummary');
  if (summary) {
    const emptyTopics = rows.filter(row => row.current === 0);
    const exactPct = ((current / target) * 100).toFixed(1);
    summary.innerHTML = `<article class="coverage-hero"><div><p class="eyebrow">OBJETIVO INTERNO DE VOLUMEN</p><strong>${exactPct}%</strong><small>${formatCount(current)} de ${formatCount(target)} preguntas propias clasificadas + ${formatCount(historicalCount)} oficiales</small></div><div class="coverage-hero-meter"><span style="width:${Math.min(100, Number(exactPct))}%"></span></div></article><article class="coverage-kpi"><span>Banco total</span><strong>${formatCount(questions.length)}</strong><small>preguntas en catálogo</small></article><article class="coverage-kpi warning"><span>Temas sin iniciar</span><strong>${emptyTopics.length}</strong><small>${emptyTopics.length === 0 ? 'todos los temas tienen preguntas' : 'temas pendientes'}</small></article><article class="coverage-kpi next"><span>Interpretación</span><strong>Cantidad, no calidad jurídica</strong><small>la revisión normativa se documenta por separado</small></article>`;
  }
  const list = document.getElementById('coverageList');
  if (list) {
    const renderBlock = (blockName, subtitle) => {
      const blockRows = rows.filter(row => row.block === blockName);
      const blockCurrent = blockRows.reduce((sum, row) => sum + row.current, 0);
      const blockTarget = blockRows.reduce((sum, row) => sum + row.target, 0);
      const blockPercent = Math.min(100, Math.round((blockCurrent / blockTarget) * 100));
      return `<article class="coverage-block-card"><header><div><p class="eyebrow">${blockName.toUpperCase()}</p><h3>${subtitle}</h3><small>${blockRows.length} temas · ${blockCurrent}/${blockTarget} preguntas</small></div><strong>${blockPercent}%</strong></header><div class="coverage-hero-meter small"><span style="width:${blockPercent}%"></span></div><div class="coverage-topic-grid">${blockRows.map(row => `<article class="topic-progress-card ${row.current ? '' : 'empty'}"><div class="topic-main"><span>${row.id.toUpperCase()}</span><strong>${row.title}</strong><small>${row.current ? `${row.current} creadas` : 'Sin arrancar'} · objetivo ${row.target}</small></div><div class="topic-progress"><b>${row.percent}%</b><i><span style="width:${row.percent}%"></span></i></div></article>`).join('')}</div></article>`;
    };
    list.innerHTML = `<section class="coverage-dashboard-board">${renderBlock('Bloque I', 'Instituciones y organización básica')}${renderBlock('Bloque II', 'Procedimiento, contratación y empleo público')}</section>`;
  }
}
function shuffleArray(array) {
  const arr = [...array];
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

function filterQuestionsByCategory(topic, questionsPool) {
  const pool = questionsPool || questions;
  const categoryFilters = {
    procedimiento: q => {
      const c = coverageTopic(q);
      return ['Procedimiento administrativo común', 'Procedimiento administrativo', 'LPAC 39/2015', 'Ley 39/2015', 'Régimen jurídico del sector público'].includes(q.topic) || (c && ['g2-12', 'g2-13'].includes(c)) || q.id.startsWith('lpac-') || q.id.startsWith('procedimiento-');
    },
    galicia: q => {
      const c = coverageTopic(q);
      return ['Organización y sector público autonómico', 'Organización de Galicia', 'Ley 16/2010', 'Xunta y Presidencia', 'Valedor del Pueblo', 'Consejo Consultivo de Galicia'].includes(q.topic) || (c && ['g1-06', 'g1-08', 'g1-09'].includes(c)) || q.id.startsWith('organizacion-') || q.id.startsWith('xunta-') || q.id.startsWith('autonomia-');
    },
    empleo: q => {
      const c = coverageTopic(q);
      return (['Empleo público de Galicia', 'TREBEP', 'Ley 2/2015'].includes(q.topic) || (c && ['g2-18', 'g2-19'].includes(c)) || q.id.startsWith('trebep-') || q.id.startsWith('empleo-galicia-')) && !q.id.startsWith('igualdad-') && !q.id.startsWith('discapacidad-');
    }
  };
  if (categoryFilters[topic]) {
    return pool.filter(categoryFilters[topic]);
  }
  return pool.filter(q => q.topic === topic || coverageTopic(q) === topic);
}

function buildSet(topic, length) {
  let pool = [];
  if (topic === 'troncal') {
    pool = questions.filter(q => { const t = coverageTopic(q); return t && t.startsWith('g1-'); });
  } else if (topic && topic.startsWith('historico')) {
    const targetTopicName = {
      historico2025: 'Histórico oficial 2025',
      historico2024: 'Histórico oficial 2024',
      historico2024pe: 'Histórico oficial 2024',
      historico2024func: 'Histórico oficial Funcionarización',
      historico2021: 'Histórico oficial Funcionarización'
    }[topic];
    const prefixMap = {
      historico2025: 'h2025-',
      historico2024: 'h2024-pe-',
      historico2024pe: 'h2024-pe-',
      historico2024func: 'h2024-func-',
      historico2021: 'h2024-func-'
    };
    const prefix = prefixMap[topic] || 'h202';
    pool = questions.filter(q => q.topic === targetTopicName || q.id.startsWith(prefix));
    if (!length) return pool; // Devuelve el examen oficial integro en su orden
  } else if (topic === 'mixto') {
    pool = questions;
  } else {
    pool = filterQuestionsByCategory(topic, questions);
  }
  if (!pool.length) pool = questions;
  const shuffled = shuffleArray(pool);
  const count = length ? Math.min(Number(length), shuffled.length) : Math.min(18, shuffled.length);
  return shuffled.slice(0, count);
}
let examTimerInterval = null;
let examTimeSeconds = 0;

function formatTimer(sec) {
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${m}:${s < 10 ? '0' : ''}${s}`;
}

function startQuiz(set, mode = 'practice') {
  activeQuiz = set;
  questionIndex = 0;
  quizMode = mode;
  examAnswers = [];
  state.sessions += 1;
  persist();

  if (examTimerInterval) clearInterval(examTimerInterval);
  if (quizMode === 'exam') {
    examTimeSeconds = activeQuiz.length * 60; // 1 minuto por pregunta
    examTimerInterval = setInterval(() => {
      examTimeSeconds--;
      const timerEl = document.getElementById('examTimerDisplay');
      if (timerEl) timerEl.textContent = `⏱ ${formatTimer(examTimeSeconds)}`;
      if (examTimeSeconds <= 0) {
        clearInterval(examTimerInterval);
        renderExamResults();
      }
    }, 1000);
  }

  showView('practice');
  document.getElementById('practiceSetup').parentElement.classList.add('hidden');
  document.getElementById('quizCard').classList.remove('hidden');
  renderQuestion();
  updateDashboard();
}

function renderQuestion() {
  const q = activeQuiz[questionIndex]; const card = document.getElementById('quizCard');
  const isExam = quizMode === 'exam';

  if (!q._shuffled || q._shuffledFor !== questionIndex) {
    const indices = [0, 1, 2, 3].slice(0, q.options.length);
    for (let i = indices.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [indices[i], indices[j]] = [indices[j], indices[i]];
    }
    const letters = ['A', 'B', 'C', 'D'];
    q._shuffledOptions = indices.map((origIdx, displayIdx) => [letters[displayIdx], q.options[origIdx][1], origIdx]);
    q._shuffledFor = questionIndex;
  }

  const selectedAns = examAnswers[questionIndex];

  card.innerHTML = `<div class="quiz-meta"><span>${isExam ? 'Simulacro Oficial' : q.topic}</span>${isExam ? `<span id="examTimerDisplay" style="font-weight:bold;color:var(--primary);">⏱ ${formatTimer(examTimeSeconds)}</span>` : ''}<span>Pregunta ${questionIndex + 1} de ${activeQuiz.length}</span></div><div class="quiz-body"><div class="question-topic">${isExam ? 'Modo examen · corrección al final' : q.quality || 'Redacción propia · pendiente de revisión'}</div><h2 class="question-text">${q.text}</h2><div class="answers">${q._shuffledOptions.map(([letter, text, origIdx]) => `<button class="answer ${selectedAns === origIdx ? 'selected' : ''}" data-answer="${origIdx}"><span class="answer-letter">${letter}</span><span>${text}</span></button>`).join('')}</div><div class="feedback hidden"></div></div><div class="quiz-footer"><span>${isExam ? 'Sin pistas · -0,25 por fallo · 0 en blanco' : '4 alternativas · aprendizaje con explicación'}</span><div style="display:flex;gap:8px;align-items:center;">${isExam ? `<button class="secondary-button leave-blank-btn">${selectedAns === -1 ? '✓ Dejada en blanco' : 'Dejar en blanco'}</button>` : ''}<button class="primary-button next-question ${isExam || selectedAns !== undefined ? '' : 'hidden'}">${questionIndex === activeQuiz.length - 1 ? 'Finalizar Examen' : 'Siguiente'} <span>→</span></button></div></div>`;

  card.querySelectorAll('.answer').forEach(button => button.addEventListener('click', () => answerQuestion(Number(button.dataset.answer))));
  
  const blankBtn = card.querySelector('.leave-blank-btn');
  if (blankBtn) {
    blankBtn.addEventListener('click', () => {
      examAnswers[questionIndex] = -1;
      nextQuestion();
    });
  }
  const nextBtn = card.querySelector('.next-question');
  if (nextBtn) {
    nextBtn.addEventListener('click', nextQuestion);
  }
}

function answerQuestion(index) {
  const q = activeQuiz[questionIndex]; const isCorrect = index === q.correct;
  if (quizMode === 'exam') {
    examAnswers[questionIndex] = index;
    document.querySelectorAll('.answer').forEach((button) => button.classList.toggle('selected', Number(button.dataset.answer) === index));
    const next = document.querySelector('.next-question');
    if (next) next.classList.remove('hidden');
    return;
  }
  state.answered.push({ id:q.id, correct:isCorrect });
  if (!isCorrect && !state.errors.includes(q.id)) state.errors.push(q.id);
  if (isCorrect) state.errors = state.errors.filter(id => id !== q.id);
  persist();
  document.querySelectorAll('.answer').forEach((button) => {
    const btnAns = Number(button.dataset.answer);
    button.disabled = true;
    button.classList.toggle('correct', btnAns === q.correct);
    button.classList.toggle('incorrect', btnAns === index && !isCorrect);
  });
  const feedback = document.querySelector('.feedback');
  feedback.classList.remove('hidden');
  feedback.innerHTML = `<h3>${isCorrect ? 'Correcta. Buen criterio.' : 'Aquí está la clave.'}</h3><p>${q.explanation}</p><ul class="why-list">${q.options.map(([letter], i) => `<li><strong>${letter}.</strong> ${q.whys[i]}</li>`).join('')}</ul><div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-top:12px;"><a class="source-link" href="${q.sourceUrl}" target="_blank" rel="noreferrer">Base legal: ${q.source} ↗</a>${q.originUrl ? `<a class="source-link" href="${q.originUrl}" target="_blank" rel="noreferrer">Examen original ↗</a>` : ''}<button type="button" class="text-button" onclick="window.openFeedbackDialog('${q.id}')" style="font-size:12px;color:var(--muted);text-decoration:underline;">💬 Reportar errata o sugerencia</button></div>`;
  const next = document.querySelector('.next-question'); next.classList.remove('hidden'); updateDashboard(); renderErrors();
}

function renderExamResults() {
  if (examTimerInterval) { clearInterval(examTimerInterval); examTimerInterval = null; }
  const results = activeQuiz.map((q, index) => {
    const selected = examAnswers[index];
    const isBlank = selected === undefined || selected === null || selected === -1;
    const isCorrect = !isBlank && selected === q.correct;
    return { q, selected, isBlank, correct: isCorrect };
  });
  const correct = results.filter(r => r.correct).length;
  const blank = results.filter(r => r.isBlank).length;
  const wrong = results.length - correct - blank;
  const net = Math.max(0, correct - (wrong * 0.25));

  results.forEach(({ q, isBlank, correct }) => {
    if (!isBlank) {
      state.answered.push({ id: q.id, correct });
      if (!correct && !state.errors.includes(q.id)) state.errors.push(q.id);
      if (correct) state.errors = state.errors.filter(id => id !== q.id);
    }
  });
  persist();
  updateDashboard();
  renderErrors();
  const card = document.getElementById('quizCard');
  card.innerHTML = `<div class="quiz-meta"><span>Resultado del simulacro</span><span>${activeQuiz.length} preguntas</span></div><div class="quiz-body"><div class="exam-summary"><div><span class="stat-label">Aciertos (+1,00)</span><strong>${correct}</strong></div><div><span class="stat-label">En blanco (0,00)</span><strong>${blank}</strong></div><div><span class="stat-label">Fallos (-0,25)</span><strong>${wrong}</strong></div><div><span class="stat-label">Nota neta</span><strong>${net.toFixed(2)}</strong></div></div><div class="exam-review">${results.map(({ q, selected, isBlank, correct }) => `<article class="exam-review-item ${isBlank ? 'blank' : (correct ? 'correct' : 'incorrect')}"><p class="eyebrow">${q.topic}</p><h3>${q.text}</h3><p><strong>Tu respuesta:</strong> ${isBlank ? '⚪ Dejada en blanco (0 puntos)' : `${q.options[selected]?.[0] || '—'} · ${q.options[selected]?.[1] || ''}`}</p><p><strong>Correcta:</strong> ${q.options[q.correct][0]} · ${q.options[q.correct][1]}</p><p>${q.explanation}</p><ul class="why-list">${q.options.map(([letter], i) => `<li><strong>${letter}.</strong> ${q.whys[i]}</li>`).join('')}</ul><a class="source-link" href="${q.sourceUrl}" target="_blank" rel="noreferrer">Base legal: ${q.source} ↗</a></article>`).join('')}</div></div><div class="quiz-footer"><span>Resultados consolidados en tu perfil local</span><button class="primary-button finish-exam">Volver al inicio <span>→</span></button></div>`;
  card.querySelector('.finish-exam').addEventListener('click', () => { card.classList.add('hidden'); document.getElementById('practiceSetup').parentElement.classList.remove('hidden'); showView('dashboard'); });
}

function finishPractice() {
  const card = document.getElementById('quizCard');
  card.innerHTML = `<div class="quiz-meta"><span>Sesión de Práctica Completada</span><span>${activeQuiz.length} preguntas</span></div><div class="quiz-body"><div class="exam-summary" style="grid-template-columns: 1fr;"><div><span class="stat-label">🎉 Sesión finalizada</span><strong>¡Buen trabajo de estudio!</strong></div></div><p style="margin-top:16px;color:var(--text);line-height:1.6;">Tus respuestas e identificadores de errores han sido guardados en tu perfil local para reforzar en futuros repasos.</p></div><div class="quiz-footer"><span>Progreso actualizado</span><button class="primary-button finish-practice">Volver al panel <span>→</span></button></div>`;
  card.querySelector('.finish-practice').addEventListener('click', () => {
    card.classList.add('hidden');
    document.getElementById('practiceSetup').parentElement.classList.remove('hidden');
    showView('dashboard');
  });
}

function nextQuestion() {
  if (questionIndex < activeQuiz.length - 1) {
    questionIndex += 1;
    renderQuestion();
  } else {
    if (quizMode === 'exam') {
      renderExamResults();
    } else {
      finishPractice();
    }
  }
}

window.addEventListener('hashchange', () => {
  const hashView = viewFromHash();
  if (hashView) showView(hashView, { updateHash: false });
});

document.querySelectorAll('.nav-link').forEach(link => link.addEventListener('click', e => { e.preventDefault(); showView(link.dataset.view); }));
document.querySelectorAll('[data-view-target]').forEach(button => button.addEventListener('click', () => showView(button.dataset.viewTarget)));
document.querySelectorAll('.start-test').forEach(button => button.addEventListener('click', () => startQuiz(buildSet(button.dataset.set, 5))));
document.querySelectorAll('.start-historical').forEach(button => button.addEventListener('click', e => startQuiz(buildSet(e.currentTarget.dataset.set), 'exam')));
document.getElementById('createTest').addEventListener('click', () => startQuiz(buildSet(document.getElementById('topicSelect').value, document.getElementById('lengthSelect').value)));
document.getElementById('simulationStart').addEventListener('click', () => startQuiz(buildSet('mixto', 18), 'exam'));

function applyUserProfile(name) {
  if (!name) return;
  try { localStorage.setItem('opoA2UserName', name); } catch (_) {}
  const initial = name.charAt(0).toUpperCase();
  document.querySelectorAll('.profile strong').forEach(el => el.textContent = name);
  document.querySelectorAll('.avatar').forEach(el => el.textContent = initial);
  const headerGreeting = document.querySelector('#dashboard .page-header h1');
  if (headerGreeting) headerGreeting.textContent = `Buenos días, ${name}.`;
}

function setAuthState(mode) {
  const isAuthenticatedOrGuest = mode === 'authenticated' || mode === 'guest' || mode === true;
  document.documentElement.dataset.authState = isAuthenticatedOrGuest ? 'authenticated' : 'unauthenticated';
  document.documentElement.dataset.authMode = mode === 'guest' ? 'guest' : (mode === 'authenticated' || mode === true ? 'supabase' : 'none');
}

function loadSavedProfile() {
  try {
    const savedName = localStorage.getItem('opoA2UserName');
    if (savedName && savedName !== 'Invitado') {
      applyUserProfile(savedName);
      setAuthState('guest');
      document.querySelectorAll('.profile small').forEach(el => el.textContent = 'Perfil local · Modo invitado');
    } else {
      localStorage.removeItem('opoA2UserName');
      setAuthState('unauthenticated');
    }
  } catch (_) {
    setAuthState('unauthenticated');
  }
}

let supabaseClient = null;

const resetPasswordModal = document.getElementById('resetPasswordModal');

function openResetPasswordModal() {
  if (resetPasswordModal) {
    const status = document.getElementById('resetPasswordStatus');
    if (status) status.textContent = '';
    resetPasswordModal.showModal();
  }
}

function initSupabase(url, key) {
  if (window.supabase && url && key) {
    supabaseClient = window.supabase.createClient(url, key);

    const hash = window.location.hash || '';
    if (hash.includes('error_code=otp_expired') || hash.includes('error=access_denied')) {
      const pageStatus = document.getElementById('authPageStatusText');
      const modalStatus = document.getElementById('authStatusText');
      const msg = 'El enlace de recuperación ha caducado o ya fue utilizado. Solicita un nuevo enlace desde "¿Olvidaste tu contraseña?".';
      if (pageStatus) pageStatus.textContent = msg;
      if (modalStatus) modalStatus.textContent = msg;
    } else if (hash.includes('type=recovery') || hash.includes('access_token=')) {
      setAuthState('authenticated');
      setTimeout(openResetPasswordModal, 300);
    }

    supabaseClient.auth.onAuthStateChange((event, session) => {
      if (event === 'PASSWORD_RECOVERY') {
        setAuthState('authenticated');
        setTimeout(openResetPasswordModal, 300);
      }
    });
    checkAuthUser();
  }
}

initSupabase('https://mquigtfqvznwnovzjudf.supabase.co', 'sb_publishable_lTjPgPWghN-fPVwBm7yyRA_ekPeh7PF');

async function checkAuthUser() {
  const logoutBtn = document.getElementById('logoutBtn');
  if (logoutBtn) logoutBtn.classList.remove('hidden');
  if (!supabaseClient) { loadSavedProfile(); return; }
  try {
    const { data, error } = await supabaseClient.auth.getSession();
    if (data && data.session && data.session.user) {
      const user = data.session.user;
      const name = user.user_metadata?.name || user.email.split('@')[0];
      applyUserProfile(name);
      setAuthState('authenticated');
      document.querySelectorAll('.profile small').forEach(el => el.textContent = 'Sesión remota Supabase activa');
      const statusText = document.getElementById('authStatusText');
      if (statusText) statusText.textContent = `Conectado como ${user.email} · Sesión remota activa`;
    } else {
      loadSavedProfile();
    }
  } catch (err) {
    console.warn('Supabase offline or unconfigured:', err);
    loadSavedProfile();
  }
}

